import java.io.*;
import java.util.*;

public class Main {
    static String solveQuery(int[] soldIds, int ticket) {
        // your code here — return "FOUND" or "NOT FOUND"
        return "NOT FOUND";
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        for (String line = br.readLine(); line != null; line = br.readLine()) sb.append(line).append(' ');
        StringTokenizer st = new StringTokenizer(sb.toString());
        int t = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            int n = Integer.parseInt(st.nextToken());
            int q = Integer.parseInt(st.nextToken());
            int[] soldIds = new int[n];
            for (int i = 0; i < n; i++) soldIds[i] = Integer.parseInt(st.nextToken());
            for (int i = 0; i < q; i++) {
                int ticket = Integer.parseInt(st.nextToken());
                out.append(solveQuery(soldIds, ticket)).append('\n');
            }
        }
        System.out.print(out);
    }
}

